@Composable fun RootScreen(component: RootComponent) { Children(component.stack) { child -> Row(modifier = Modifier.fillMaxSize().padding(horizontal = 4.dp, vertical = 4.dp)) { Column(Modifier.padding(vertical = 4.dp).fillMaxHeight()) { ZeroDelayNeverHideTooltips { SelectableIconActionButton( AllIconsKeys.Toolwindows.ToolWindowServer, "Servers", onClick = {}, selected = true, tooltip = { Text("Servers") }, tooltipPlacement = TooltipPlacement.ComponentRect( Alignment.CenterEnd, Alignment.CenterEnd, offset = DpOffset(6.dp, 0.dp) ), extraHints = arrayOf(Size(20)), modifier = Modifier.size(32.dp) ) }
Spacer(Modifier.weight(1f))
ZeroDelayNeverHideTooltips { SelectableIconActionButton( AllIconsKeys.General.Settings, "Settings", onClick = { component.navigateTo(RootComponent.Config.Settings)}, selected = component.currentActive(RootComponent.Config.Settings), tooltip = { Text("Settings") }, tooltipPlacement = TooltipPlacement.ComponentRect( Alignment.CenterEnd, Alignment.CenterEnd, offset = DpOffset(6.dp, 0.dp) ), extraHints = arrayOf(Size(20)), modifier = Modifier.size(32.dp), colorFilter = ColorFilter.tint(AccentColor.Default.resolveColor(isDarkTheme()))
) } ZeroDelayNeverHideTooltips { SelectableIconActionButton( AllIconsKeys.General.ShowInfos, "Info", onClick = { component.navigateTo(RootComponent.Config.Info) }, selected = component.currentActive(RootComponent.Config.Info), tooltip = { Text("Info") }, tooltipPlacement = TooltipPlacement.ComponentRect( Alignment.CenterEnd, Alignment.CenterEnd, offset = DpOffset(6.dp, 0.dp) ), extraHints = arrayOf(Size(20)), modifier = Modifier.size(32.dp), ) } } Spacer(Modifier.width(4.dp)) Card(modifier = Modifier.weight(1f).fillMaxHeight()) { when (val instance = child.instance) { is RootComponent.Child.Info -> InfoScreen(instance.component) is RootComponent.Child.Servers -> Text("Servers Screen - Coming Soon") is RootComponent.Child.Settings -> Text("Settings Screen - Coming Soon") } } } } }

